-    // We are preparing for evacuation.
+    // At start of evacation, we do NOT compute_old_generation_balance()
@@ -316,6 +315,0 @@
-    if (heap->mode()->is_generational()) {
-      ShenandoahGenerationalHeap* gen_heap = ShenandoahGenerationalHeap::heap();
